-- ============================================================
-- Greener Herd – Static / Reference Data  (vaccines + medicines)
-- Generated from Medicine_List.xlsx
--
-- Run against the static-data schema.
-- Safe to re-run: tables are created IF NOT EXISTS then TRUNCATEd.
-- ============================================================

-- Shared enum -------------------------------------------------
DO $$ BEGIN
  CREATE TYPE mena_restriction_level AS ENUM ('Low', 'Medium', 'High');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;


-- ============================================================
-- VACCINES  (100 rows)
-- ============================================================
CREATE TABLE IF NOT EXISTS vaccines (
  id                      INT            PRIMARY KEY,
  vaccine_name            VARCHAR(200)   NOT NULL,
  target_species          VARCHAR(100)   NOT NULL,
  age_groups              VARCHAR(200)   NOT NULL,
  pregnant_lactating_safe VARCHAR(200)   NOT NULL,
  diseases_prevented      TEXT           NOT NULL,
  instructions_for_use    TEXT           NOT NULL,
  dosage                  VARCHAR(200)   NOT NULL,
  meat_withdrawal_days    INT            NOT NULL DEFAULT 0,
  milk_withdrawal_days    INT            NOT NULL DEFAULT 0,
  mena_restrictions       mena_restriction_level NOT NULL DEFAULT 'Low',
  banned_countries        VARCHAR(500)   NOT NULL DEFAULT 'None',
  created_at              TIMESTAMPTZ    NOT NULL DEFAULT NOW()
);

TRUNCATE TABLE vaccines CASCADE;

