-- ============================================================
-- MEDICINES  (202 rows)
-- ============================================================
CREATE TABLE IF NOT EXISTS medicines (
  id                        INT            PRIMARY KEY,
  medicine_name             VARCHAR(200)   NOT NULL,
  active_ingredient         VARCHAR(200)   NOT NULL,
  category                  VARCHAR(100)   NOT NULL,
  target_species            VARCHAR(100)   NOT NULL,
